#!/usr/bin/env python3
# Piece 1c-B-write (dream-os) — binder WRITE endpoints (B, step 2).
#
# The screen's hands on the books — but through Kriya's primitives, never raw SQL.
# Every endpoint calls executeKriyaTool (the SAME engine the chat path uses), so a
# button tap and a chat dispatch share ONE discipline: ground-truth read, old->new
# confession, immutable event trail, money parsing, money-door firewall. The screen
# is just another caller of Kriya's hands. Create mirrors the proven enquiryBinder
# path (kriya_client opens, then chain field writes). Tool names (kriya_*) are never
# exposed — the front end speaks REST (/money-edit, /stage, ...); firewall holds.

import base64, os, sys
ROOT = os.getcwd()
BW_B64 = ""

CORE = os.path.join(ROOT, "src", "api", "vendor", "core.js")
# mount AFTER cabinet (which 1c-B-cabinet added). Fall back to context if cabinet absent.
ANCHOR_CAB = "router.use('/cabinet',  require('./cabinet'));"
ANCHOR_CTX = "router.use('/context',  require('./context'));"
MOUNT = "router.use('/binders',  require('./binderWrite'));"

def main():
    vdir = os.path.join(ROOT, "src", "api", "vendor")
    if not os.path.isdir(vdir):
        print("ERROR: run from dream-os repo root."); sys.exit(1)

    open(os.path.join(vdir, "binderWrite.js"), "wb").write(base64.b64decode(BW_B64))
    print("OK: wrote src/api/vendor/binderWrite.js")

    s = open(CORE, encoding="utf-8").read()
    if "require('./binderWrite')" in s:
        print("SKIP: /binders already mounted")
    elif ANCHOR_CAB in s:
        open(CORE, "w", encoding="utf-8").write(s.replace(ANCHOR_CAB, ANCHOR_CAB + "\n" + MOUNT, 1))
        print("OK: mounted /binders after /cabinet")
    elif ANCHOR_CTX in s:
        open(CORE, "w", encoding="utf-8").write(s.replace(ANCHOR_CTX, ANCHOR_CTX + "\n" + MOUNT, 1))
        print("OK: mounted /binders after /context (cabinet not present)")
    else:
        print("WARN: no mount anchor found — mount /binders by hand"); sys.exit(1)

    print("\nPiece 1c-B-write written. Screen writes now flow through Kriya's primitives.")

if __name__ == "__main__":
    main()
